export class Value {
  grad = 0
  _backward = () => {}

  constructor(data, children = [], op = '') {
    this.data = data
    this._prev = new Set(children)
    this._op = op
  }

  add(other) {
    const o = other instanceof Value ? other : new Value(other)
    const out = new Value(this.data + o.data, [this, o], '+')
    out._backward = () => {
      this.grad += out.grad
      o.grad += out.grad
    }
    return out
  }

  mul(other) {
    const o = other instanceof Value ? other : new Value(other)
    const out = new Value(this.data * o.data, [this, o], '*')
    out._backward = () => {
      this.grad += o.data * out.grad
      o.grad += this.data * out.grad
    }
    return out
  }

  pow(n) {
    const out = new Value(this.data ** n, [this], '**' + n)
    out._backward = () => {
      this.grad += n * this.data ** (n - 1) * out.grad
    }
    return out
  }

  relu() {
    const out = new Value(this.data < 0 ? 0 : this.data, [this], 'ReLU')
    out._backward = () => {
      this.grad += (out.data > 0 ? 1 : 0) * out.grad
    }
    return out
  }

  neg() {
    return this.mul(-1)
  }

  sub(other) {
    return this.add(other instanceof Value ? other.neg() : -other)
  }

  div(other) {
    const o = other instanceof Value ? other : new Value(other)
    return this.mul(o.pow(-1))
  }

  backward() {
    const topo = []
    const visited = new Set()
    const build = (v) => {
      if (visited.has(v)) return
      visited.add(v)
      for (const child of v._prev) build(child)
      topo.push(v)
    }
    build(this)
    this.grad = 1
    for (const v of topo.reverse()) v._backward()
  }
}

